// src/pages/FarmDetail.js
import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css';
import './Manager.css';
import speciesData from '../data/speciesData';

function FarmDetail() {
  const { farmId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');

  const [farm, setFarm] = useState(null);
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  // State chính của form
  const [activityFormData, setActivityFormData] = useState({
    speciesName: '',
    scientificName: '',
    date: '',
    increase: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
    decrease: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
    reasonForChange: '',
  });

  // State điều khiển giao diện
  const [selectedOldSpecies, setSelectedOldSpecies] = useState('');
  const [selectedNewSpecies, setSelectedNewSpecies] = useState('');
  const [isManualEntry, setIsManualEntry] = useState(false);

  const fetchFarmDetails = useCallback(async () => {
    setLoading(true);
    setError('');
    try {
      const resFarm = await axios.get(`http://localhost:10000/api/farms/${farmId}`, { headers: { Authorization: `Bearer ${token}` } });
      setFarm(resFarm.data);
      if (resFarm.data.loaiDongVatRung && resFarm.data.loaiDongVatRung[0]) {
        setSelectedOldSpecies(resFarm.data.loaiDongVatRung[0].tenLamSan);
        setActivityFormData(prev => ({ ...prev, speciesName: resFarm.data.loaiDongVatRung[0].tenLamSan }));
      }
      
      const resActivities = await axios.get(`http://localhost:10000/api/farm-activities/${farmId}`, { headers: { Authorization: `Bearer ${token}` } });
      setActivities(resActivities.data);
    } catch (err) {
      setError('Could not load farm details.');
    } finally {
      setLoading(false);
    }
  }, [farmId, token]);

  useEffect(() => {
    if (farmId && token) fetchFarmDetails();
  }, [farmId, token, fetchFarmDetails]);

  // HÀM XỬ LÝ RIÊNG CHO CÁC Ô INPUT SỐ LỒNG NHAU
  const handleNestedChange = (e) => {
    const { name, value } = e.target;
    const [mainField, subField, prop] = name.split('.');
    setActivityFormData(prev => ({
      ...prev,
      [mainField]: { ...prev[mainField], [subField]: { ...prev[mainField][subField], [prop]: parseInt(value, 10) || 0 } },
    }));
  };

  // HÀM XỬ LÝ RIÊNG CHO CÁC Ô INPUT THÔNG THƯỜNG (text, date, nhập tay)
  const handleSimpleChange = (e) => {
    const { name, value } = e.target;
    setActivityFormData(prev => ({ ...prev, [name]: value }));
  };
  
  // HÀM XỬ LÝ RIÊNG CHO DROPDOWN CŨ
  const handleOldSpeciesChange = (e) => {
    const value = e.target.value;
    setSelectedOldSpecies(value);
    setActivityFormData(prev => ({ ...prev, speciesName: value, scientificName: '' }));
    // Reset lựa chọn mới
    setSelectedNewSpecies('');
    setIsManualEntry(false);
  };
  
  // HÀM XỬ LÝ RIÊNG CHO DROPDOWN MỚI
  const handleNewSpeciesChange = (e) => {
    const value = e.target.value;
    setSelectedNewSpecies(value);
    setSelectedOldSpecies(''); // Reset lựa chọn cũ
    
    if (value === 'manual' || value === 'Nhập thủ công') {
      setIsManualEntry(true);
      setActivityFormData(prev => ({ ...prev, speciesName: '', scientificName: '' }));
    } else {
      setIsManualEntry(false);
      const matched = speciesData.find(s => s.tenLamSan === value);
      setActivityFormData(prev => ({
        ...prev,
        speciesName: matched ? matched.tenLamSan : '',
        scientificName: matched ? matched.tenKhoaHoc : ''
      }));
    }
  };

  const handleAddActivity = async (e) => {
    e.preventDefault();
    try {
      const dataToSend = { ...activityFormData, farm: farmId };
      await axios.post(`http://localhost:10000/api/farm-activities`, dataToSend, { headers: { Authorization: `Bearer ${token}` } });
      setMessage('Thêm bản ghi thành công!');
      fetchFarmDetails(); // Tải lại dữ liệu
    } catch (err) {
      setError(err.response?.data?.message || 'Thêm bản ghi thất bại.');
    }
  };

  if (loading) return <div className="form-container"><p>Đang tải...</p></div>;
  if (error) return <div className="form-container"><p style={{ color: 'red' }}>Lỗi: {error}</p></div>;
  if (!farm) return <div className="form-container"><p>Không tìm thấy thông tin.</p></div>;

  return (
    <div className="form-container">
      <h2>👁️ Logbook: {farm.tenCoSo}</h2>
      
      <h3>Add New Tracking Record:</h3>
      {message && <div className="success-message">{message}</div>}
      <form onSubmit={handleAddActivity} className="modern-form">
        
        <div className="form-group">
          <label>Species Name (đã có):</label>
          <select name="speciesName" value={selectedOldSpecies} onChange={handleOldSpeciesChange}>
            <option value="">-- Select species --</option>
            {farm.loaiDongVatRung?.map((species, index) => (
              <option key={index} value={species.tenLamSan}>{species.tenLamSan}</option>
            ))}
          </select>
        </div>

        <div className="form-group-full-width" style={{ border: '1px dashed #007bff', padding: '15px', borderRadius: '8px' }}>
          <label style={{ fontWeight: 'bold', display: 'block', marginBottom: '10px', color: '#007bff' }}>
            Hoặc đăng ký loài mới
          </label>
          <div className="form-grid">
            <div className="form-group">
              <label htmlFor="newSpeciesSelection">Tên loài mới:</label>
              <select id="newSpeciesSelection" value={selectedNewSpecies} onChange={handleNewSpeciesChange}>
                <option value="">-- Chọn hoặc nhập thủ công --</option>
                {speciesData.map((species, index) => (
                  <option key={index} value={species.tenLamSan}>{species.tenLamSan}</option>
                ))}
              </select>
            </div>
            {!isManualEntry && selectedNewSpecies && !selectedNewSpecies.includes("thủ công") && (
              <div className="form-group">
                <label>Tên khoa học:</label>
                <input type="text" value={activityFormData.scientificName} readOnly disabled />
              </div>
            )}
            {isManualEntry && (
              <>
                <div className="form-group">
                  <label>Tên loài (nhập tay):</label>
                  <input type="text" name="speciesName" value={activityFormData.speciesName} onChange={handleSimpleChange} required />
                </div>
                <div className="form-group">
                  <label>Tên khoa học (nhập tay):</label>
                  <input type="text" name="scientificName" value={activityFormData.scientificName} onChange={handleSimpleChange} />
                </div>
              </>
            )}
          </div>
        </div>
        
        <div className="form-grid">
          <div className="form-group">
            <label>Date Recorded:</label>
            <input type="date" name="date" value={activityFormData.date} onChange={handleSimpleChange} required />
          </div>
          <div className="form-group">
            <label>Reason for Change:</label>
            <input type="text" name="reasonForChange" value={activityFormData.reasonForChange} onChange={handleSimpleChange} />
          </div>
        </div>

        <div className="form-grid">
            <div className="form-section-wrapper">
                <h4>Increase:</h4>
                <input type="number" name="increase.parents.male" value={activityFormData.increase.parents.male} onChange={handleNestedChange} />
                {/* Các input khác cho Increase dùng handleNestedChange */}
            </div>
            <div className="form-section-wrapper">
                <h4>Decrease:</h4>
                <input type="number" name="decrease.parents.male" value={activityFormData.decrease.parents.male} onChange={handleNestedChange} />
                {/* Các input khác cho Decrease dùng handleNestedChange */}
            </div>
        </div>
        
        <button type="submit" className="submit-button">Add Record</button>
      </form>

      <h3>Tracking History:</h3>
      {/* ... Bảng hiển thị giữ nguyên ... */}
    </div>
  );
}

export default FarmDetail;
